package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withFirstRecordAsHeader();

        assertNotNull(result, "Resulting CSVFormat should not be null");
        // withFirstRecordAsHeader() returns withHeader().withSkipHeaderRecord()
        // So header should not be null and skipHeaderRecord should be true
        assertNotNull(result.getHeader(), "Header should not be null");
        assertTrue(result.getSkipHeaderRecord(), "skipHeaderRecord should be true");

        // Original format remains unchanged (immutable)
        assertNull(format.getHeader(), "Original format header should be null");
        assertFalse(format.getSkipHeaderRecord(), "Original format skipHeaderRecord should be false");
    }
}
